		p, err := getPermissionsFromSingleGrant(r, a.scopeMap[r.ScopeId][0], Action)
		if err != nil {
			return nil, err
		}
		return p, nil

	case len(a.scopeMap[r.ScopeId]) >= 1 && scopeIsUnknown(r.Type):
		for _, grant := range a.scopeMap[r.ScopeId] {
			p, err := getPermissionsFromSingleGrant(r, grant, Action)
			if err != nil {
				return nil, err
			}
			if p.All || (len(p.ResourceIds) > 0 && scopeMatches(r.Resource)) {
				return p, nil
			}
		}

